+    client_identity: &str,
+    server_identity: &str,
+    encryption_key_id: &str,
+    signing_key_id: &str,
+    epoch: ControlEpoch,
+    timestamp: u64,
+    root_secret: &RootSecret,
+) -> [u8; SIGNATURE_LEN] {
+    let preimage = build_handshake_preimage(
+        session_id,
+        client_identity,
+        server_identity,
+        encryption_key_id,
+        signing_key_id,
+        epoch.value(),
+        timestamp,
+    );
+    compute_handshake_mac(&preimage, epoch, root_secret)
+}
